class ASTNode:
    def __init__(
        self,
        node_type: str,
        value: float | None = None,
        op: str | None = None,
        left: "ASTNode | None" = None,
        right: "ASTNode | None" = None,
        operand: "ASTNode | None" = None,
    ):
        self.type = node_type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


def __repr__(self) -> str:
    if self.type == "number":
        return f"ASTNode('number', value={self.value})"
    elif self.type == "binop":
        return f"ASTNode('binop', op='{self.op}', left={self.left}, right={self.right})"
    elif self.type == "unary":
        return f"ASTNode('unary', op='{self.op}', operand={self.operand})"
    return f"ASTNode({self.type})"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("No valid tokens found")

    return parse_expression(tokens, 0)[0]


def tokenize(expression: str) -> list[str]:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            num_str = c
            i += 1
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                num_str += expression[i]
                i += 1
            tokens.append(num_str)
        else:
            raise ValueError(f"Invalid token: '{c}'")

    return tokens


def parse_expression(tokens: list[str], precedence: int) -> tuple[ASTNode, int]:
    left, pos = parse_primary(tokens)

    while pos < len(tokens):
        op = tokens[pos]
        if op not in "+-*/":
            break

        op_precedence = get_precedence(op)
        if op_precedence < precedence:
            break

        pos += 1
        right, new_pos = parse_expression(tokens, op_precedence + 1)

        left = ASTNode("binop", op=op, left=left, right=right)
        pos = new_pos

    return left, pos


def parse_primary(tokens: list[str]) -> tuple[ASTNode, int]:
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens[0]

    if token == "(":
        pos = 1
        node, pos = parse_expression(tokens[pos:], 0)
        if pos >= len(tokens) or tokens[pos] != ")":
            raise ValueError("Unmatched parentheses")
        return node, pos + 1

    elif token == "-":
        pos = 1
        operand, pos = parse_primary(tokens[pos:])
        return ASTNode("unary", op="-", operand=operand), pos

    elif token == "+":
        pos = 1
        operand, pos = parse_primary(tokens[pos:])
        return operand, pos

    elif token.replace(".", "", 1).isdigit():
        try:
            value = float(token)
            return ASTNode("number", value=value), 1
        except ValueError:
            raise ValueError(f"Invalid number: '{token}'")

    else:
        raise ValueError(f"Unexpected token: '{token}'")


def get_precedence(op: str) -> int:
    if op in "*/":
        return 2
    elif op in "+-":
        return 1
    return 0


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return float(node.value) if node.value is not None else 0.0

    elif node.type == "binop":
        left_val = evaluate(node.left) if node.left is not None else 0.0
        right_val = evaluate(node.right) if node.right is not None else 0.0

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

    elif node.type == "unary":
        operand_val = evaluate(node.operand) if node.operand is not None else 0.0
        if node.op == "-":
            return -operand_val

    raise ValueError(f"Unknown node type: {node.type}")
